-- 1. Repurpose body-proportions as Frame
UPDATE luv_chassis_modules SET name = 'Frame', description = 'Overall body type, height, build, somatotype, and fat distribution' WHERE slug = 'body-proportions';
UPDATE luv_chassis_modules SET parameter_schema = '[{"key": "height", "label": "Height", "type": "measurement", "tier": "basic", "description": "Standing height", "units": ["cm", "in"], "defaultUnit": "cm", "min": 140, "max": 200, "step": 1, "default": {"value": 170, "unit": "cm"}}, {"key": "build", "label": "Build", "type": "enum", "tier": "basic", "options": ["petite", "slim", "athletic", "average", "curvy", "muscular", "plus", "rubenesque"], "default": "athletic"}, {"key": "age_appearance", "label": "Apparent Age", "type": "text", "tier": "basic", "description": "Age range the character appears to be"}, {"key": "somatotype", "label": "Somatotype", "type": "enum", "tier": "intermediate", "options": ["ectomorph", "ecto-mesomorph", "mesomorph", "meso-endomorph", "endomorph", "endo-ectomorph"], "default": "mesomorph", "description": "Body type classification \u2014 ectomorph (lean/long), mesomorph (muscular/medium), endomorph (soft/round)"}, {"key": "body_fat", "label": "Body Fat Level", "type": "enum", "tier": "intermediate", "options": ["very-low", "low", "athletic", "moderate", "high", "very-high"], "default": "athletic", "description": "Overall body fat \u2014 affects how muscle and bone landmarks show through"}, {"key": "fat_distribution", "label": "Fat Distribution", "type": "enum", "tier": "intermediate", "options": ["android", "gynoid", "even", "lower-body-dominant", "upper-body-dominant"], "default": "gynoid", "description": "Where fat preferentially deposits \u2014 gynoid (hips/thighs), android (midsection)"}, {"key": "weight", "label": "Weight", "type": "measurement", "tier": "advanced", "description": "Body weight", "units": ["kg"], "defaultUnit": "kg", "min": 35, "max": 150, "step": 0.5, "default": {"value": 60, "unit": "kg"}}, {"key": "overall_symmetry", "label": "Body Symmetry", "type": "enum", "tier": "advanced", "options": ["highly-symmetric", "slight-asymmetry", "noticeable-asymmetry"], "default": "highly-symmetric"}]'::jsonb WHERE slug = 'body-proportions';

