UPDATE luv_chassis_modules SET parameter_schema = '[{"key": "shoulder_width", "label": "Shoulder Width", "type": "measurement", "tier": "basic", "description": "Biacromial breadth, point to point", "units": ["cm", "in"], "defaultUnit": "cm", "min": 30, "max": 50, "step": 0.5, "default": {"value": 38, "unit": "cm"}}, {"key": "shoulder_shape", "label": "Shoulder Shape", "type": "enum", "tier": "basic", "options": ["sloped", "slightly-sloped", "straight", "squared", "rounded", "muscular"], "default": "slightly-sloped"}, {"key": "neck_length", "label": "Neck Length", "type": "enum", "tier": "basic", "options": ["short", "average", "long", "swan"], "default": "average"}, {"key": "neck_circumference", "label": "Neck Circumference", "type": "measurement", "tier": "intermediate", "description": "Base of neck", "units": ["cm", "in"], "defaultUnit": "cm", "min": 28, "max": 45, "step": 0.5, "default": {"value": 33, "unit": "cm"}}, {"key": "neck_shape", "label": "Neck Shape", "type": "enum", "tier": "intermediate", "options": ["slender", "average", "thick", "muscular", "wide"], "default": "slender"}, {"key": "clavicle_visibility", "label": "Clavicle Visibility", "type": "enum", "tier": "intermediate", "options": ["hidden", "subtle", "visible", "defined", "prominent", "hollowed"], "default": "visible", "description": "How much the collarbones show \u2014 prominent reads elegant in fashion"}, {"key": "clavicle_shape", "label": "Clavicle Shape", "type": "enum", "tier": "intermediate", "options": ["straight", "gently-curved", "S-curved", "prominent-angle"], "default": "gently-curved"}, {"key": "trapezius", "label": "Trapezius Definition", "type": "enum", "tier": "advanced", "options": ["flat", "subtle", "defined", "muscular", "very-muscular"], "default": "subtle", "description": "Muscle definition from neck to shoulder"}, {"key": "deltoid", "label": "Deltoid Definition", "type": "enum", "tier": "advanced", "options": ["soft", "subtle", "defined", "capped", "very-muscular"], "default": "subtle", "description": "Shoulder cap muscle definition"}, {"key": "shoulder_to_hip", "label": "Shoulder-to-Hip Ratio", "type": "ratio", "tier": "clinical", "ratioLabels": ["Shoulder", "Hip"], "min": 0, "max": 1, "step": 0.05, "default": {"a": 0.45, "b": 0.55}}]'::jsonb WHERE slug = 'shoulders-neck';
UPDATE luv_chassis_modules SET parameter_schema = '[{"key": "circumference", "label": "Bust Circumference", "type": "measurement", "tier": "basic", "description": "Fullest point around chest", "units": ["cm", "in"], "defaultUnit": "cm", "min": 70, "max": 130, "step": 0.5, "default": {"value": 88, "unit": "cm"}}, {"key": "shape", "label": "Breast Shape", "type": "enum", "tier": "basic", "options": ["athletic", "natural-round", "teardrop", "full-round", "bell", "east-west", "side-set", "conical", "omega", "pendulous"], "default": "natural-round", "description": "Overall breast shape classification"}, {"key": "size_descriptor", "label": "Size", "type": "enum", "tier": "basic", "options": ["very-small", "small", "small-medium", "medium", "medium-large", "large", "very-large", "extremely-large"], "default": "medium"}, {"key": "underbust", "label": "Underbust", "type": "measurement", "tier": "intermediate", "description": "Band measurement directly below bust", "units": ["cm", "in"], "defaultUnit": "cm", "min": 60, "max": 110, "step": 0.5, "default": {"value": 74, "unit": "cm"}}, {"key": "projection", "label": "Projection", "type": "enum", "tier": "intermediate", "options": ["flat", "subtle", "moderate", "prominent", "very-prominent", "extreme"], "default": "moderate", "description": "How far the breast projects from the chest wall in profile"}, {"key": "position", "label": "Vertical Position", "type": "enum", "tier": "intermediate", "options": ["high", "medium-high", "medium", "medium-low", "low"], "default": "medium-high", "description": "Where the breast apex sits on the torso"}, {"key": "spacing", "label": "Breast Spacing", "type": "enum", "tier": "intermediate", "options": ["touching", "close-set", "average", "wide-set", "very-wide-set"], "default": "average", "description": "Gap between the breasts at the sternum"}, {"key": "upper_pole", "label": "Upper Pole Fullness", "type": "enum", "tier": "intermediate", "options": ["concave", "minimal", "moderate", "full", "very-full"], "default": "moderate", "description": "Fullness above the nipple \u2014 affects whether breasts appear ''top-heavy''"}, {"key": "nipple_position", "label": "Nipple Direction", "type": "enum", "tier": "advanced", "options": ["upward", "forward", "slightly-lateral", "lateral", "downward"], "default": "forward"}, {"key": "nipple_size", "label": "Nipple Size", "type": "enum", "tier": "advanced", "options": ["very-small", "small", "medium", "large", "very-large"], "default": "medium"}, {"key": "nipple_shape", "label": "Nipple Shape", "type": "enum", "tier": "advanced", "options": ["flat", "slightly-protruding", "protruding", "prominent", "inverted"], "default": "slightly-protruding"}, {"key": "areola_size", "label": "Areola Size", "type": "enum", "tier": "advanced", "options": ["very-small", "small", "medium", "large", "very-large"], "default": "medium", "description": "Diameter of the areolar region"}, {"key": "areola_color", "label": "Areola Color", "type": "color", "tier": "advanced", "default": "#C4868A"}, {"key": "areola_texture", "label": "Areola Texture", "type": "enum", "tier": "advanced", "options": ["smooth", "slightly-textured", "bumped", "puffy"], "default": "slightly-textured", "description": "Montgomery glands visibility and puffiness"}, {"key": "asymmetry", "label": "Asymmetry", "type": "enum", "tier": "advanced", "options": ["symmetric", "very-slight", "slight", "noticeable", "significant"], "default": "very-slight", "description": "Degree of size or shape difference between breasts"}, {"key": "bust_to_underbust", "label": "Bust-Underbust Difference", "type": "measurement", "tier": "clinical", "description": "Bust minus underbust \u2014 determines effective cup size (e.g. 14cm \u2248 D)", "units": ["cm", "in"], "defaultUnit": "cm", "min": 0, "max": 30, "step": 0.5, "default": {"value": 14, "unit": "cm"}}, {"key": "ptosis", "label": "Ptosis Grade", "type": "enum", "tier": "clinical", "options": ["none", "pseudoptosis", "grade-I", "grade-II", "grade-III"], "default": "none", "description": "Clinical breast ptosis \u2014 none (nipple above fold) through grade-III (nipple below fold, pointing down)"}]'::jsonb WHERE slug = 'bust';
