ption": "Indentation between hip bone and upper thigh (violin hips)"}, {"key": "navel_shape", "label": "Navel Shape", "type": "enum", "tier": "advanced", "options": ["vertical-slit", "horizontal", "round", "oval", "T-shaped", "outie", "hooded"], "default": "vertical-slit"}, {"key": "navel_depth", "label": "Navel Depth", "type": "enum", "tier": "advanced", "options": ["shallow", "average", "deep", "very-deep"], "default": "average"}, {"key": "navel_position", "label": "Navel Position", "type": "enum", "tier": "advanced", "options": ["high", "centered", "low"], "default": "centered"}, {"key": "linea_alba", "label": "Linea Alba", "type": "enum", "tier": "advanced", "options": ["invisible", "faint", "visible", "dark"], "default": "faint", "description": "Vertical midline from sternum to pubis \u2014 more visible with pigmentation or pregnancy"}, {"key": "abdominal_definition", "label": "Abdominal Muscle Definition", "type": "enum", "tier": "advanced", "options": ["none", "hint-of-line", "two-pack", "four-pack", "six-pack", "eight-pack"], "default": "hint-of-line"}, {"key": "oblique_definition", "label": "Oblique Definition", "type": "enum", "tier": "advanced", "options": ["hidden", "subtle", "defined", "cut", "very-cut"], "default": "subtle", "description": "Side abdominal muscle lines"}, {"key": "love_handles", "label": "Love Handles", "type": "enum", "tier": "advanced", "options": ["none", "subtle", "soft", "moderate", "prominent"], "default": "subtle"}, {"key": "torso_to_leg", "label": "Torso-to-Leg Ratio", "type": "ratio", "tier": "clinical", "ratioLabels": ["Torso", "Legs"], "min": 0, "max": 1, "step": 0.05, "default": {"a": 0.45, "b": 0.55}}]'::jsonb WHERE slug = 'torso';
